BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?wp ?name WHERE {
  ?wp rdf:type vocab:package .
  ?wp vocab:NamedElement_name ?name .
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("work package")) || CONTAINS(LCASE(STR(?name)), LCASE("work%20package")) || CONTAINS(LCASE(STR(?name)), LCASE("wbs")) || CONTAINS(LCASE(STR(?name)), LCASE("tmt")))
  FILTER NOT EXISTS { ?wp vocab:Element_owner ?parent . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?wp ?wpName WHERE {
  ?root rdf:type vocab:package ;
        vocab:NamedElement_name ?rootName .
  FILTER(LCASE(STR(?rootName)) = LCASE("Work%20Packages"))

  { ?root vocab:Package_packagedElement ?wp . }
  UNION
  { ?root vocab:Package_nestedPackage ?wp . }
  ?wp rdf:type vocab:package ;
      vocab:NamedElement_name ?wpName .

}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?child ?childType ?childName WHERE {
  ?root rdf:type vocab:package ;
        vocab:NamedElement_name "Work%20Packages" .

  { ?root vocab:Element_ownedElement ?child . }
  UNION
  { ?root vocab:Package_packagedElement ?child . }
  UNION
  { ?root vocab:Package_nestedPackage ?child . }
  UNION
  { ?root vocab:Namespace_member ?child . }

  ?child rdf:type ?childType .
  OPTIONAL { ?child vocab:NamedElement_name ?childName . }
}
LIMIT 25

